/**
 * Unit tests for session-heartbeat-finalizer (#1885).
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync, readFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

const mockedCwd = vi.hoisted(() => ({ value: '/' }));
vi.mock('../../lib/paths.js', async (orig) => {
  const actual = (await orig()) as Record<string, unknown>;
  return { ...actual, getProjectDir: () => mockedCwd.value };
});

import { sessionHeartbeatFinalizer } from '../../stop/session-heartbeat-finalizer.js';
import {
  getStateFilePath,
  writeSessionStateAtomic,
  type SessionState,
} from '../../lib/session-state.js';
import { createTestContext } from '../fixtures/test-context.js';

let workspace: string;
let testCtx: ReturnType<typeof createTestContext>;

beforeEach(() => {
  workspace = mkdtempSync(join(tmpdir(), 'ork-finalizer-'));
  vi.stubEnv('HOME', workspace);
  testCtx = createTestContext();
});

afterEach(() => {
  vi.unstubAllEnvs();
  try {
    rmSync(workspace, { recursive: true, force: true });
  } catch {
    /* best-effort */
  }
});

describe('sessionHeartbeatFinalizer', () => {
  beforeEach(() => {
    mockedCwd.value = join(workspace, 'platform');
  });

  it('returns silent success when no prior state file exists', () => {
    // No publisher ever wrote anything — finalizer should NOT create a stub.
    const r = sessionHeartbeatFinalizer(
      { tool_name: 'session-end', session_id: 'sid', tool_input: {} },
      testCtx,
    );
    expect(r.continue).toBe(true);
    expect(r.suppressOutput).toBe(true);
  });

  it('marks an existing state as completed', () => {
    const existing: SessionState = {
      repo: 'platform',
      session_id: 'sid-123',
      started_at: '2026-05-20T10:00:00Z',
      last_heartbeat: '2026-05-20T11:00:00Z',
      status: 'running',
      last_commit: { sha: 'abc1234', msg: 'feat: x' },
      last_push: null,
      last_pr: null,
    };
    const p = getStateFilePath('platform', 'sid-123', workspace);
    writeSessionStateAtomic(p, existing);

    sessionHeartbeatFinalizer(
      { tool_name: 'session-end', session_id: 'sid-123', tool_input: {} },
      testCtx,
    );

    const after = JSON.parse(readFileSync(p, 'utf8'));
    expect(after.status).toBe('completed');
    // started_at preserved
    expect(after.started_at).toBe('2026-05-20T10:00:00Z');
    // commit preserved
    expect(after.last_commit).toEqual({ sha: 'abc1234', msg: 'feat: x' });
    // heartbeat bumped
    expect(after.last_heartbeat).not.toBe('2026-05-20T11:00:00Z');
  });

  it('silently no-ops on missing session_id', () => {
    const r = sessionHeartbeatFinalizer(
      { tool_name: 'session-end', session_id: '', tool_input: {} },
      testCtx,
    );
    expect(r.continue).toBe(true);
    expect(r.suppressOutput).toBe(true);
  });
});
